inline int hotspot_index(int x, int y, int z, int nx, int ny)
{
    return x + y * nx + z * nx * ny;
}

__kernel void hotspotOpt1(__global const float *pIn,
                          __global const float *tIn,
                          __global float *tOut,
                          const float stepDivCap,
                          const int nx,
                          const int ny,
                          const int nz,
                          const float ce,
                          const float cw,
                          const float cn,
                          const float cs,
                          const float ct,
                          const float cb,
                          const float cc)
{
    const int x = (int)get_global_id(0);
    const int y = (int)get_global_id(1);

    if (x >= nx || y >= ny)
        return;

    for (int z = 0; z < nz; z++)
    {
        const int c = hotspot_index(x, y, z, nx, ny);

        const int w = (x == 0)      ? c : c - 1;
        const int e = (x == nx - 1) ? c : c + 1;
        const int n = (y == 0)      ? c : c - nx;
        const int s = (y == ny - 1) ? c : c + nx;
        const int b = (z == 0)      ? c : c - nx * ny;
        const int t = (z == nz - 1) ? c : c + nx * ny;

        tOut[c] = cc * tIn[c]
                + cw * tIn[w]
                + ce * tIn[e]
                + cs * tIn[s]
                + cn * tIn[n]
                + cb * tIn[b]
                + ct * tIn[t]
                + stepDivCap * pIn[c]
                + ct * 80.0f;
    }
}
